  ('bookkeeper-moex-01166', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '記帳士應付懲戒者，由記帳士懲戒委員會處理之。依「記帳士懲戒委員會與懲戒覆審委員會組織及審議 規則」之規定，記帳士懲戒委員會置委員9人，其中，記帳士代表應有幾人？', '["未規定應有記帳士代表", "1人", "2人", "3人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
